export default function LoginPage() {
  const [accounts, setAccounts]     = useState<Account[]>([]);
  const [loading, setLoading]       = useState(true);
  const [creating, setCreating]     = useState(false);
  const [showProModal, setShowProModal] = useState(false);

  async function refresh() {
    const accs = await api.accounts.list();
    setAccounts(accs);
  }

  useEffect(() => {
    refresh().catch(() => {}).finally(() => setLoading(false));
  }, []);

  async function handleCreate() {
    setCreating(true);
    try {
      await api.accounts.create();
      await refresh();
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      if (msg.includes("ACCOUNT_LIMIT")) {
        setShowProModal(true);
      }
      // 其他错误静默（网络问题等极少场景）
    } finally {
      setCreating(false);
    }
  }

  async function handleDelete(id: number) {
    await api.accounts.delete(id);
    await refresh();
  }

  if (loading) return <p className="text-sm mt-4" style={{ color: "var(--muted)" }}>加载中…</p>;

  return (
    <div className="space-y-4">
      {showProModal && <ProUpgradeModal onClose={() => setShowProModal(false)} />}

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-semibold">账号管理</h1>
          <p className="text-xs mt-1" style={{ color: "var(--muted)" }}>
            小红书账号 · MCP 登录 · 飞书表格 · 生成排期
          </p>
        </div>
        <button onClick={handleCreate} disabled={creating}
          className="text-xs px-3 py-1.5 rounded disabled:opacity-50"
          style={{ background: "var(--accent)", color: "#fff" }}>
          {creating ? "创建中…" : "+ 新增账号"}
        </button>
      </div>

      {accounts.length === 0 ? (
        <div className="rounded-lg p-8 text-center"
          style={{ background: "var(--surface)", border: "1px dashed var(--border)" }}>
          <p className="text-sm mb-3" style={{ color: "var(--muted)" }}>还没有账号</p>
          <button onClick={handleCreate} disabled={creating}
            className="text-xs px-4 py-2 rounded"
            style={{ background: "var(--accent)", color: "#fff" }}>
            {creating ? "创建中…" : "创建第一个账号"}
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          {accounts.map((acc, i) => (
            <AccountLoginCard key={acc.id} account={acc}
              onDelete={handleDelete}
              defaultCollapsed={accounts.length > 1 && i > 0} />
          ))}
        </div>
      )}
    </div>
  );
}
